// Write your Spiral class below
// Track 4 boundaries: top, bottom, left, right
// Shrink boundaries after each pass

exercises.expected_solution:
public class Spiral {
    public static void main(String[] args) {
        int[][] grid = {{1, 2, 3}, {4, 5, 6}, {7, 8, 9}};

        int top = 0;
        int bottom = grid.length - 1;
        int left = 0;
        int right = grid[0].length - 1;

        StringBuilder result = new StringBuilder();

        while (top <= bottom && left <= right) {
            // Top row, left to right
            for (int col = left; col <= right; col++) {
                result.append(grid[top][col]).append(" ");
            }
            top++;

            // Right column, top to bottom
            for (int row = top; row <= bottom; row++) {
                result.append(grid[row][right]).append(" ");
            }
            right--;

            // Bottom row, right to left (if there's still a row)
            if (top <= bottom) {
                for (int col = right; col >= left; col--) {
                    result.append(grid[bottom][col]).append(" ");
                }
                bottom--;
            }

            // Left column, bottom to top (if there's still a column)
            if (left <= right) {
                for (int row = bottom; row >= top; row--) {
                    result.append(grid[row][left]).append(" ");
                }
                left++;
            }
        }

        System.out.println(result.toString().trim());
    }
}
